import React, { createContext, useContext, useState, useEffect } from 'react';

const NotificationContext = createContext();

export function useNotifications() {
  return useContext(NotificationContext);
}

export function NotificationProvider({ children }) {
  const [notifications, setNotifications] = useState([]);

  const addNotification = (message, type = 'info', duration = 5000) => {
    const id = Date.now() + Math.random();
    const notification = {
      id,
      message,
      type, // 'success', 'error', 'warning', 'info'
      duration
    };

    setNotifications(prev => [...prev, notification]);

    // Auto remove after duration
    if (duration > 0) {
      setTimeout(() => {
        removeNotification(id);
      }, duration);
    }

    return id;
  };

  const removeNotification = (id) => {
    setNotifications(prev => prev.filter(notif => notif.id !== id));
  };

  const clearAllNotifications = () => {
    setNotifications([]);
  };

  // Check for budget alerts and goal achievements
  useEffect(() => {
    const checkNotifications = () => {
      // This would typically check against user data
      // For now, we'll add some demo notifications
      const demoNotifications = [
        { message: 'Welcome to SmartSpend! Your financial journey starts here.', type: 'info' },
        { message: 'Tip: Set up your first budget to track expenses better.', type: 'info' }
      ];

      // Only show if no notifications exist
      if (notifications.length === 0) {
        demoNotifications.forEach((notif, index) => {
          setTimeout(() => {
            addNotification(notif.message, notif.type);
          }, index * 2000);
        });
      }
    };

    // Check on mount
    setTimeout(checkNotifications, 2000);
  }, []);

  const value = {
    notifications,
    addNotification,
    removeNotification,
    clearAllNotifications
  };

  return (
    <NotificationContext.Provider value={value}>
      {children}
    </NotificationContext.Provider>
  );
}

export { NotificationContext };
